package controller;
import koneksi.Koneksi;import model.Pemasukan;import java.io.*;import java.sql.*;import java.time.LocalDate;import java.util.*;import com.itextpdf.kernel.pdf.*;import com.itextpdf.layout.*;import com.itextpdf.layout.element.*;
public class PemasukanController{public boolean simpan(Pemasukan p)throws SQLException{String sql="INSERT INTO pemasukan(tanggal,id_siswa,id_kategori_pemasukan,nominal,keterangan,created_by) VALUES(?,?,?,?,?,?)";try(PreparedStatement ps=Koneksi.getConnection().prepareStatement(sql)){ps.setDate(1,p.getTanggal());if(p.getIdSiswa()==null)ps.setNull(2,Types.INTEGER);else ps.setInt(2,p.getIdSiswa());ps.setInt(3,p.getIdKategoriPemasukan());ps.setDouble(4,p.getNominal());ps.setString(5,p.getKeterangan());ps.setInt(6,p.getCreatedBy());return ps.executeUpdate()>0;}}public boolean bayarSpp(int siswa,int bulan,int tahun,double nominal,int user)throws SQLException{try(PreparedStatement ps=Koneksi.getConnection().prepareStatement("UPDATE spp_tagihan SET status='LUNAS',tanggal_bayar=CURDATE() WHERE id_siswa=? AND bulan=? AND tahun=?")){ps.setInt(1,siswa);ps.setInt(2,bulan);ps.setInt(3,tahun);ps.executeUpdate();}return simpan(new Pemasukan(0,java.sql.Date.valueOf(LocalDate.now()),siswa,1,nominal,"Pembayaran SPP "+bulan+"/"+tahun,user));}public List<Object[]> riwayat(LocalDate a,LocalDate b,String kat)throws SQLException{List<Object[]>l=new ArrayList<>();String sql="SELECT p.id_pemasukan,p.tanggal,COALESCE(s.nama_siswa,'-'),kp.nama_kategori,p.nominal,p.keterangan FROM pemasukan p LEFT JOIN siswa s ON s.id_siswa=p.id_siswa JOIN kategori_pemasukan kp ON kp.id=p.id_kategori_pemasukan WHERE p.tanggal BETWEEN ? AND ? AND kp.nama_kategori LIKE ? ORDER BY p.tanggal DESC";try(PreparedStatement ps=Koneksi.getConnection().prepareStatement(sql)){ps.setDate(1,java.sql.Date.valueOf(a));ps.setDate(2,java.sql.Date.valueOf(b));ps.setString(3,"%"+kat+"%");try(ResultSet r=ps.executeQuery()){while(r.next())l.add(new Object[]{r.getInt(1),r.getDate(2),r.getString(3),r.getString(4),r.getDouble(5),r.getString(6)});}}return l;}public void cetakKuitansiPdf(File f,String siswa,double nominal,String ket)throws IOException{try(PdfWriter w=new PdfWriter(f);PdfDocument pdf=new PdfDocument(w);Document d=new Document(pdf)){d.add(new Paragraph("Kuitansi Pembayaran").setBold().setFontSize(18));d.add(new Paragraph("Siswa: "+siswa));d.add(new Paragraph("Nominal: "+util.UIUtils.rupiah(nominal)));d.add(new Paragraph("Keterangan: "+ket));}}}
